// === AGENT V2 SMOKE — Vision Loop Happy Path ===

// 1. Agent-Status prüfen
const status = await client.adjustments.status();
assert(status.available === true, "Agent muss verfügbar sein");
assert(status.provider === "anthropic", "Provider muss anthropic sein");

// 2. Session erstellen
const session = await createAdjustmentSession(importId, "reader", selection);
assert(session.status === "open");

// 3. Nachricht mit Screenshot senden
const result = await client.adjustments.appendMessage({
  sessionId: session.id,
  content: "Die Sternchen sollen nicht sichtbar sein",
  screenshot: MOCK_SCREENSHOT_BASE64,
  markup: "<li>**Bold text** normal text</li>",
});

// 4. Agent-Antwort prüfen
assert(result.session.messages.length >= 2, "Mindestens User + Agent Nachricht");
const lastMsg = result.session.messages.at(-1);
assert(lastMsg.role === "assistant", "Letzte Nachricht ist vom Agent");

// 5. Regel wurde erstellt
const rules = listFormatRules(importId, "reader");
const newRule = rules.find(r => r.sourceSessionId === session.id);
assert(newRule, "Agent hat eine Regel erstellt");

// === AGENT V2 SMOKE — Offline Fallback ===

// 6. Ohne API-Key: Status gibt unavailable zurück
// (env manipulation)
const offlineStatus = await client.adjustments.status();
assert(offlineStatus.available === false);
assert(offlineStatus.reason?.includes("API"));

// === AGENT V2 SMOKE — Fehlerfälle ===

// 7. Nachricht ohne Session → NOT_FOUND
try {
  await client.adjustments.appendMessage({
    sessionId: "non-existent",
    content: "test",
  });
  assert(false, "Sollte Fehler werfen");
} catch (e) {
  assert(e.code === "NOT_FOUND");
}

// 8. Leerer Content → Validierungsfehler
try {
  await client.adjustments.appendMessage({
    sessionId: session.id,
    content: "",
  });
  assert(false, "Sollte Fehler werfen");
} catch (e) {
  assert(e instanceof Error);
}
